INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('baldurkarlsson-renderdoc', 'RenderDoc', 'RenderDoc is a free MIT licensed stand-alone graphics debugger that allows quick and easy single-frame capture and detailed introspection of any application using Vulkan, D3D11, OpenGL & OpenGL ES or D3D12 across Windows 7 - 10, Linux, Android, Stadia, or Nintendo Switch.', 'Design', 'baldurkarlsson-renderdoc-icon', '', 0, 'https://renderdoc.org/', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('balena-balenacli', 'balena-cli', 'The balena CLI is a Command Line Interface for balenaCloud or openBalena. It is a software tool available for Windows, macOS and Linux, used through a command prompt / terminal window. It can be used interactively or invoked in scripts. The balena CLI builds on the balena API and the balena SDK, and can also be directly imported in Node.js applications. The balena CLI is an open-source project on GitHub, and your contribution is also welcome!', 'Development', 'balena-balenacli-icon', '', 0, 'https://www.balena.io/docs/reference/balena-cli/', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('balsamiq-wireframes', 'Balsamiq Wireframes', 'Balsamiq Wireframes is a rapid low-fidelity UI wireframing tool that reproduces the experience of sketching on a notepad or whiteboard, but using a computer.
It really forces you to focus on structure and content, avoiding lengthy discussions about colors and details that should come later in the process.
Wireframes is FAST: you will generate more ideas, so you can throw out the bad ones and discover the best solutions.', 'Development', 'balsamiq-wireframes-icon', '', 0, 'https://balsamiq.com/wireframes/', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('bandicamcompany-bandicam', 'Bandicam', 'Bandicam is a lightweight screen recorder software for Windows that can capture anything on your PC screen as a high-quality video.
This app also makes it possible to record a certain area on a PC screen, or capture a game that uses the DirectX/OpenGL/Vulkan graphics technologies.
Bandicam will help you carry out a screen capture with high compression ratio, while preserving the video quality of the original work, and provide performance far superior to other screen capture software that provides similar functions.', 'Games', 'bandicamcompany-bandicam-icon', '', 0, 'https://www.bandicam.com/', NULL);
