INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('bitrecover-windowslivemailconverter', 'BitRecover Windows Live Mail Converter Wizard', 'This program gives the facility to migrate from WLM to multiple generic file extensions such as PST, MSG, EML, EMLX, TXT, MBOX, HTML, MHT, XPS, RTF, DOC, Windows Live Mail, CSV, Gmail, Yahoo, TIFF, BMP, GIF, JPEG, PNG, PDF, NSF, TGZ, OLM, etc. It gives freedom to transfer folders from Windows Live Mail to various cloud-based email services and servers, i.e., Gmail, Yahoo, Outlook.com, Office 365, Exchange Server, Hosted Exchange Server, G Suite, IBM Verse, Amazon WorkMail, IMAP Server, etc. The tool has an inbuilt feature to automatically load WLM folders in the software panel from the default storage location. It has another option to load emails manually from any other storage location. Moreover, after the start, the tool is will automatically load overall Windows Live Mail databases in the software panel, including all email folders in Windows Explorer style.', 'Development', 'bitrecover-windowslivemailconverter-icon', '', 0, 'https://www.bitrecover.com/windows-live-mail-converter', NULL);
