INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('brunonova-collision', 'Collision', 'In this game you control a green ball. Using your mouse or keyboard, you have to avoid hitting the ever increasing number of red balls that are moving around in the game window. The moment you touch one of them, the game is over.

The game has three difficulty levels and two modes:
- Time: you have to dodge the red balls for as long as possible. Every few seconds a new red ball appears. The longer you last, the higher the score will be.
- Coins: you have to catch as many coins as you can. Every few coins a new red ball appears. The more coins you gather, the higher the score will be.

During the game different bonuses can also appear. These can provide either a positive or a negative effect.
', 'Games', 'brunonova-collision-icon', '', 0, 'https://github.com/brunonova/collision2', NULL);
INSERT OR REPLACE INTO apps (id, name, description, category, icon, linux_alternative, popularity, homepage, alternative_to) VALUES ('brunonova-drmips', 'DrMIPS', 'DrMIPS is a graphical simulator of the MIPS processor to support computer  architecture teaching and learning. It is intuitive, versatile and configurable.
The simulator is available not only for personal computers but also for Android devices, especially tablets.
DrMIPS was created under the Master’s dissertation entitled Tool to Support Computer Architecture Teaching and Learning at the Faculty of Engineering of the University of Porto, in Portugal.
Requires Java 8 or later.', 'Design', 'brunonova-drmips-icon', '', 0, 'https://brunonova.github.io/drmips/', NULL);
