INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('1', 'adobe-photoshop', NULL, 'Silver', 'Bottles (Soda)', 'Works using the Soda runner in Bottles. The installation fails on the first try, so you must use the offline installer. Decent performance.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('2', 'microsoft-office', NULL, 'Bronze', 'Wine', 'Word and Excel work okay, but advanced macros, plugins, and cloud licensing crash the application.', '2026-06-13');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('3', 'autodesk-autocad', NULL, 'Garbage', 'CrossOver', 'Impossible to install. Fails at the licensing service and does not render the viewport canvas.', '2026-06-10');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('4', 'imageline-flstudio', NULL, 'Platinum', 'Lutris', 'Using the latest Lutris-GE version. Audio works perfectly with Pipewire-ALSA. Loads all VSTs with no issues.', '2026-06-12');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('5', 'epicgames-epicgameslauncher', NULL, 'Platinum', 'Lutris', 'Runs well using Lutris or Bottles. However, using the native Heroic Games Launcher is highly recommended as a superior alternative.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('6', 'discord-discord', NULL, 'Native', 'Native', 'Works perfectly native. Install the Flatpak version for sandbox security.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('7', 'spotify-spotify', NULL, 'Native', 'Native', 'Official Linux client is available and works perfectly. Zero lag.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('8', 'rarlab-winrar', NULL, 'Gold', 'Wine', 'Runs flawlessly under Wine, but PeaZip is a native Linux tool and works much better.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('9', 'bittorrent-utorrent', NULL, 'Silver', 'Wine', 'Runs in Wine but has ads. Recommend switching to qBittorrent which is native and ad-free.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('10', 'akeo-rufus', NULL, 'Garbage', 'Wine', 'Low level USB disk writer cannot access hardware through Wine translation. Use Ventoy natively instead.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('11', 'google-chrome', NULL, 'Native', 'Native', 'Google Chrome has a native version for Linux and works perfectly.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('12', 'valve-steam', NULL, 'Native', 'Native', 'Steam runs natively on Linux. Highly recommended to use the official package or Flatpak.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('13', 'adobe-premiere-pro', NULL, 'Garbage', 'Wine', 'Does not install. Creative Cloud desktop app crashes and licensing fails. Use DaVinci Resolve or Kdenlive instead.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('14', 'adobe-illustrator', NULL, 'Bronze', 'Wine', 'Older versions (CS6) run okay, but modern CC versions crash during startup. Inkscape is a great native alternative.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('15', 'igor-7zip', NULL, 'Gold', 'Wine', 'Runs perfectly, but PeaZip is native and integrates with the Linux desktop environment much better.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('16', 'whatsapp-desktop', NULL, 'Native', 'Native', 'Use WhatsApp Web in browser or native open-source clients like ZapZap.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('17', 'videolan-vlc', NULL, 'Native', 'Native', 'VLC is native to Linux and works perfectly.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('18', 'notepad-plusplus', NULL, 'Platinum', 'Wine', 'Runs flawlessly under Wine. However, native editors like VS Code or Notepadqq are recommended.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('19', 'teamviewer-teamviewer', NULL, 'Native', 'Native', 'Official native TeamViewer package is available for Linux and works great.', '2026-06-14');
