INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('r-paint', 'microsoft-paint', NULL, 'Gold', 'Wine', 'Can be run using Wine, but native alternatives like Pinta or Drawing are much faster and integrate better.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('r-snippingtool', 'microsoft-snippingtool', NULL, 'Garbage', 'Wine', 'Low-level Windows desktop capture APIs do not work properly through Wine. Use native screenshot tools like Spectacle or Flameshot.', '2026-06-14');
INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('r-taskmanager', 'microsoft-taskmanager', NULL, 'Garbage', 'Wine', 'Cannot monitor Linux system resources through Wine translation. Use GNOME/KDE System Monitor or htop natively.', '2026-06-14');
