INSERT OR REPLACE INTO reports (id, app_id, github_user, rating, runner, details, date) VALUES ('r-visio', 'microsoft-visio', NULL, 'Silver', 'Wine', 'Can run under Wine with some font configuration tweaks. Draw.io is a great native web/desktop alternative.', '2026-06-14');
